                        opacity: 0;
                        transform: translateY(50px) scale(0.95);
                    }
                    100% {
                        opacity: 1;
                        transform: translateY(0) scale(1);
                    }
                }

                /* Header */
                .login-header {
                    text-align: center;
                    margin-bottom: 50px;
                    position: relative;
                }

                .brand-icon {
                    width: 80px;
                    height: 80px;
                    background: linear-gradient(135deg, #00d4ff, #0072ff);
                    border-radius: 20px;
                    margin: 0 auto 25px;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    font-size: 36px;
                    color: white;
                    box-shadow: 0 15px 40px rgba(0, 112, 255, 0.4);
