                .input-field:focus {
                    outline: none;
                    border-color: #00d4ff;
                    background: rgba(20, 25, 45, 0.9);
                    box-shadow: 0 0 0 4px rgba(0, 212, 255, 0.15);
                    transform: translateY(-2px);
